from bisect import bisect_left
from typing import List

class Solution:
    def minAbsoluteDifference(self, nums: List[int], x: int) -> int:
        n = len(nums)
        sorted_list = []
        min_diff = float('inf')

        for i in range(n):
            # Check elements that are at least x indices apart
            if i >= x:
                # Find the closest value in sorted_list to nums[i]
                pos = bisect_left(sorted_list, nums[i])
                if pos < len(sorted_list):
                    min_diff = min(min_diff, abs(nums[i] - sorted_list[pos]))
                if pos > 0:
                    min_diff = min(min_diff, abs(nums[i] - sorted_list[pos - 1]))
            # Insert nums[i] into the sorted list
            bisect_left(sorted_list, nums[i])
            sorted_list.insert(pos, nums[i])

        return min_diff
